import { Link } from 'react-router-dom';

import FeatureSection from '../components/FeatureSection';




// Category Card Component
function CategoryCard({ icon, name }) {
  return (
    <Link to="/events">
      <div className="group bg-gradient-to-br from-gray-50 to-gray-100 p-8 rounded-2xl text-center hover:shadow-xl transform hover:-translate-y-2 transition-all duration-300 cursor-pointer">
        <div className="text-5xl mb-4 transform group-hover:scale-110 transition-transform duration-300">
          {icon}
        </div>
        <div className="text-lg font-semibold text-gray-800">
          {name}
        </div>
      </div>
    </Link>
  );
}

export default Home;
